  "$schema": "https://anthropic.com/claude-code/marketplace.schema.json",
  "name": "sc4sap",
  "description": "SuperClaude for SAP (sc4sap) transforms Claude Code into a full-stack SAP development assistant. It connects to your SAP system via the MCP ABAP ADT server (150+ tools) to create, read, update, and delete ABAP objects directly — classes, function modules, reports, CDS views, and more. The plugin includes 25 SAP-specialized agents (core dev agents + BC consultant + 14 module consultants for SD, MM, FI, CO, PP, PS, PM, QM, TR, HCM, WM, TM, Ariba, BW), workflow skills (create-program with execution-mode gate and parallel Phase 4/6, create-object, analyze-code, analyze-symptom, analyze-cbo-obj, deep-interview, team orchestration, release, setup, and an internal-only session trust bootstrap), and built-in SPRO configuration reference with BAPI lists, transaction codes, and representative workflows for every module. Designed for SAP consultants, ABAP developers, and Basis administrators working with On-Premise S/4HANA systems.",
  "owner": {
    "name": "paek seunghyun"
  },
  "plugins": [
    {
      "name": "sc4sap",
      "description": "Claude Code plugin for SAP ABAP development on On-Premise S/4HANA — 25 specialized agents, 16 workflow skills (create-program with Phase 4/6 hardening + multi-executor split, create-object, program-to-spec, compare-programs, analyze-code/symptom/cbo-obj, ask-consultant, deep-interview, team, release, setup, internal trust-session), 4-Tier context loading, Sonnet/Opus model routing, OK_CODE binding pattern, paradigm-split Clean ABAP, and SPRO config reference for 14 modules.",
      "version": "0.6.2",
      "author": {
        "name": "paek seunghyun"
      },
      "source": "./",
      "category": "development",
      "tags": [
        "sap",
        "abap",
        "s4hana",
        "erp",
        "abap-development",
        "mcp",
        "on-premise"
      ],
      "examples": [
        {
          "title": "ABAP Class Creation & Unit Testing",
          "prompt": "Create a custom sales order validation class ZCL_SD_ORDER_VALIDATOR with methods for credit check, delivery date validation, and pricing verification. Include ABAP Unit tests for each method."
        },
        {
          "title": "Cross-Module Integration Analysis",
          "prompt": "Analyze the integration points between SD billing (VF01) and FI accounting document posting. Show me which BAPIs and user exits are involved in the billing-to-accounting flow."
        },
        {
          "title": "SPRO Configuration Reference",
          "prompt": "What SPRO configuration tables are needed to set up a new sales organization in SD? List the transaction codes and configuration sequence."
        },
        {
          "title": "Code Review & Refactoring",
          "prompt": "Review the function module Z_MM_PURCHASE_ORDER_CREATE for ABAP Clean Code violations, performance issues, and suggest refactoring to use modern ABAP syntax (inline declarations, NEW, VALUE)."
        },
        {
          "title": "Transport Management",
          "prompt": "List all open transport requests for user DEVUSER, check for inactive objects, and prepare a release summary for the transports related to the ZSD_* namespace."
        },
        {
          "title": "Debugging & Root Cause Analysis",
          "prompt": "The report ZMM_STOCK_REPORT dumps with CX_SY_OPEN_SQL_DB at line 142. Analyze the SQL statement, check the table structure, and fix the issue."
        },
        {
          "title": "Module Consultant Workflow",
          "prompt": "As an FI consultant, help me configure automatic payment program (F110) for vendor payments via bank transfer. What master data, SPRO settings, and custom development are needed?"
        },
        {
          "title": "Full Program Pipeline (create-program with execution-mode gate)",
          "prompt": "/sc4sap:create-program Create an ALV report for open purchase orders by vendor with filtering by plant, purchasing organization, and date range. Include totals and subtotals."
        }
      ]
    }
  ],
  "version": "0.6.2"
}

